// AdminDashboard.js
import React, { useState, useEffect } from 'react';
import { Box, Heading, Button, Flex, Table, Tbody, Td, Th, Thead, Tr, useToast, Input } from '@chakra-ui/react';
import axios from 'axios';
import moment from 'moment';
import * as XLSX from 'xlsx';

const AdminDashboard = () => {
  const [view, setView] = useState('realTime'); // 'realTime' or 'browseAndDownload'
  const [currentTasks, setCurrentTasks] = useState([]);
  const [allTasks, setAllTasks] = useState([]);
  const [startDate, setStartDate] = useState(null);
  const [endDate, setEndDate] = useState(null);
  const toast = useToast();

  useEffect(() => {
    if (view === 'realTime') {
      fetchCurrentTasks();
    }
  }, [view]);

  // Fetch Current Tasks for Real-Time Monitoring
  const fetchCurrentTasks = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/current-tasks', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
      });
      setCurrentTasks(response.data);
    } catch (error) {
      console.error('Error fetching current tasks:', error);
      toast({
        title: 'Error',
        description: error.response?.data?.message || 'Failed to fetch current tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  // Fetch All Tasks for Browsing and Downloading
  const fetchAllTasks = async () => {
    try {
      const token = localStorage.getItem('authToken');
      if (!token) {
        throw new Error('No authentication token found');
      }

      const response = await axios.get('http://localhost:5000/api/tasks', {
        params: {
          startDate: startDate ? startDate.toISOString() : null,
          endDate: endDate ? endDate.toISOString() : null,
        },
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      setAllTasks(response.data);
    } catch (error) {
      console.error('Error fetching tasks:', error);
      toast({
        title: 'Error',
        description: error.response?.data?.message || 'Failed to fetch tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    }
  };

  return (
    <Box maxW="80%" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={6} textAlign="center">
        Admin Dashboard
      </Heading>

      {/* Panel for Selecting View */}
      <Flex justifyContent="center" mb={6}>
        <Button colorScheme="teal" mr={4} onClick={() => setView('realTime')}>
          Real-Time Data
        </Button>
        <Button colorScheme="blue" onClick={() => setView('browseAndDownload')}>
          Browse and Download All Data
        </Button>
      </Flex>

      {/* Real-Time Data View */}
      {view === 'realTime' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Current Tasks of Team Members
          </Heading>
          <Table variant="striped" colorScheme="teal">
            <Thead>
              <Tr>
                <Th>Team Member</Th>
                <Th>Task ID</Th>
                <Th>Queue</Th>
                <Th>Time Spent (so far)</Th>
              </Tr>
            </Thead>
            <Tbody>
              {currentTasks.map(({ user, activeTask }) => (
                activeTask ? (
                  <Tr key={user.email}>
                    <Td>{`${user.firstName} ${user.lastName}`}</Td>
                    <Td>{activeTask.taskId}</Td>
                    <Td>{activeTask.queue}</Td>
                    <Td>{moment.duration(activeTask.timeSpent, 'seconds').humanize()}</Td>
                  </Tr>
                ) : (
                  <Tr key={user.email}>
                    <Td>{`${user.firstName} ${user.lastName}`}</Td>
                    <Td colSpan={3} textAlign="center">No Active Task</Td>
                  </Tr>
                )
              ))}
            </Tbody>
          </Table>
        </Box>
      )}

      {/* Browse and Download Data View */}
      {view === 'browseAndDownload' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Browse and Download Team Member Tasks
          </Heading>
          {/* Date Range Picker for Browsing Tasks */}
          <Flex justifyContent="center" mb={6}>
            <Input
              type="date"
              value={startDate ? moment(startDate).format('YYYY-MM-DD') : ''}
              onChange={(e) => setStartDate(e.target.value ? new Date(e.target.value) : null)}
              placeholder="Start Date"
              mx={2}
            />
            <Input
              type="date"
              value={endDate ? moment(endDate).format('YYYY-MM-DD') : ''}
              onChange={(e) => setEndDate(e.target.value ? new Date(e.target.value) : null)}
              placeholder="End Date"
              mx={2}
            />
            <Button colorScheme="teal" onClick={fetchAllTasks} ml={4}>
              Fetch Tasks
            </Button>
          </Flex>
        </Box>
      )}
    </Box>
  );
};

export default AdminDashboard;
